// Transform AWS Security Hub findings to ALDECI format
const timestamp = new Date().toISOString();
const findings = [];

if ($input.all()[0]?.json?.Findings) {
  for (const awsFinding of $input.all()[0].json.Findings) {
    findings.push({
      finding_id: `aws-${awsFinding.Id}`,
      finding_type: 'aws_security_hub',
      entity_type: 'resource',
      entity_id: awsFinding.Resources?.[0]?.Id || 'unknown',
      title: awsFinding.Title,
      description: awsFinding.Description,
      severity: (() => {
        const severity = awsFinding.Severity?.Label?.toLowerCase() || 'medium';
        if (severity === 'critical') return 'critical';
        if (severity === 'high') return 'high';
        if (severity === 'medium') return 'medium';
        if (severity === 'low') return 'low';
        if (severity === 'informational') return 'info';
        return 'medium';
      })(),
      cvss_score: awsFinding.Severity?.Original,
      status: awsFinding.RecordState === 'ACTIVE' ? 'open' : 'closed',
      source: 'aws',
      scanner: 'aws-security-hub',
      discovery_time: timestamp,
      aws_region: awsFinding.Resources?.[0]?.Region,
      aws_account_id: awsFinding.AwsAccountId,
      resource_type: awsFinding.Resources?.[0]?.Type,
      remediation: awsFinding.Remediation?.Recommendation?.Text,
      references: awsFinding.References?.map(r => r.Url) || [],
      compliance_status: awsFinding.Compliance?.Status,
      standards: awsFinding.Types || [],
      first_observed_at: awsFinding.FirstObservedAt,
      last_observed_at: awsFinding.LastObservedAt
    });
  }
}

return { items: findings };

// Transform Azure Defender assessments to ALDECI format
const timestamp = new Date().toISOString();
const findings = [];

if ($input.all()[0]?.json?.value) {
  for (const assessment of $input.all()[0].json.value) {
    const properties = assessment.properties || {};
    const displayData = properties.displayData || {};

    findings.push({
      finding_id: `azure-${assessment.id}`,
      finding_type: 'azure_defender',
      entity_type: 'resource',
      entity_id: properties.resourceDetails?.Id || 'unknown',
      title: displayData.title || assessment.name,
      description: displayData.description || '',
      severity: (() => {
        const severity = properties.metadata?.severity?.toLowerCase() || 'medium';
        if (severity === 'high') return 'high';
        if (severity === 'medium') return 'medium';
        if (severity === 'low') return 'low';
        return 'medium';
      })(),
      status: properties.status?.firstEvaluationDate ? 'open' : 'pending',
      source: 'azure',
      scanner: 'azure-defender',
      discovery_time: timestamp,
      azure_subscription: properties.resourceDetails?.SubscriptionId,
      azure_resource_type: properties.resourceDetails?.ResourceType,
      remediation_steps: displayData.remediationDescription,
      references: properties.metadata?.url ? [properties.metadata.url] : [],
      control_id: properties.metadata?.assessmentType,
      last_scan_date: properties.status?.lastEvaluationDate
    });
  }
}

return { items: findings };

// Transform GCP Security Command Center findings to ALDECI format
const timestamp = new Date().toISOString();
const findings = [];

if ($input.all()[0]?.json?.listAssetsResponse?.assets) {
  for (const asset of $input.all()[0].json.listAssetsResponse.assets) {
    const securityMarks = asset.securityMarks?.marks || {};
    const resourceProperties = asset.resourceProperties || {};

    findings.push({
      finding_id: `gcp-${asset.name}`,
      finding_type: 'gcp_scc',
      entity_type: 'resource',
      entity_id: asset.name,
      title: asset.displayName || resourceProperties.displayName || 'GCP Asset Finding',
      description: `GCP Asset: ${resourceProperties.name}`,
      severity: (() => {
        const riskLevel = securityMarks['risk-level']?.toLowerCase() || 'medium';
        if (riskLevel === 'critical') return 'critical';
        if (riskLevel === 'high') return 'high';
        if (riskLevel === 'medium') return 'medium';
        if (riskLevel === 'low') return 'low';
        return 'info';
      })(),
      status: asset.state === 'ACTIVE' ? 'open' : 'closed',
      source: 'gcp',
      scanner: 'gcp-security-command-center',
      discovery_time: timestamp,
      gcp_project_id: resourceProperties.projectId,
      gcp_resource_type: asset.resourceType,
      gcp_asset_type: resourceProperties.type || asset.assetType,
      location: resourceProperties.location,
      security_marks: securityMarks,
      create_time: asset.createTime,
      update_time: asset.updateTime
    });
  }
}

return { items: findings };

// Merge all cloud findings from parallel branches
const allFindings = [];

// Collect from all input items (merged from AWS, Azure, GCP branches)
for (const item of $input.all()) {
  if (Array.isArray(item.json)) {
    allFindings.push(...item.json);
  } else if (item.json && typeof item.json === 'object') {
    allFindings.push(item.json);
  }
}

return { items: allFindings };

// Generate summary statistics
const findings = $input.all().flatMap(item => Array.isArray(item.json) ? item.json : [item.json]);
const timestamp = new Date().toISOString();

const summary = {
  timestamp: timestamp,
  total_findings: findings.length,
  by_severity: {
    critical: findings.filter(f => f.severity === 'critical').length,
    high: findings.filter(f => f.severity === 'high').length,
    medium: findings.filter(f => f.severity === 'medium').length,
    low: findings.filter(f => f.severity === 'low').length,
    info: findings.filter(f => f.severity === 'info').length
  },
  by_source: {
    aws: findings.filter(f => f.source === 'aws').length,
    azure: findings.filter(f => f.source === 'azure').length,
    gcp: findings.filter(f => f.source === 'gcp').length
  },
  by_status: {
    open: findings.filter(f => f.status === 'open').length,
    closed: findings.filter(f => f.status === 'closed').length,
    pending: findings.filter(f => f.status === 'pending').length
  }
};

return { items: [summary] };
